#include<bits/stdc++.h>
using namespace std;
int n,a[505],dps[505],dpx[505],sxd=INT_MIN;
int main(void){
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	for(int i=1;i<=n;i++){
		int ans=1;
		for(int j=1;j<=i;j++)if(a[i]>a[j])ans=max(ans,dps[j]+1);
		dps[i]=ans;
	}
	for(int i=n;i>=1;i--){
		int ans=1;
		for(int j=1;j<=n;j++)if(a[i]>a[j])ans=max(ans,dpx[j]+1);
		dpx[i]=ans;
	}
	for(int i=1;i<=n;i++)sxd=max(sxd,dps[i]+dpx[i]-1);
	cout<<n-sxd;
	return false;
}
